import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Как это работает?","description":"","frontmatter":{},"headers":[],"relativePath":"ru/advanced/how-it-works.md","filePath":"ru/advanced/how-it-works.md"}'),l={name:"ru/advanced/how-it-works.md"};function i(s,e,n,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="как-это-работает" tabindex="-1"><i class="ph ph-lightbulb"></i> Как это работает? <a class="header-anchor" href="#как-это-работает" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-lightbulb&quot;&gt;&lt;/i&gt; Как это работает?&quot;">​</a></h1><p>Секрет эффективности WebAP кроется в его модульности и математическом подходе. Плагин не пытается &quot;угадать&quot; причину лагов или слепо сбросить разрешение экрана.</p><p>Вся система работает как четко отлаженный конвейер, состоящий из трех главных слоев: <strong>Tracker</strong>, <strong>Indexer</strong> и <strong>Scalers</strong>.</p><h2 id="конвеиер-принятия-решении" tabindex="-1"><i class="ph ph-tree-view"></i> Конвейер принятия решений <a class="header-anchor" href="#конвеиер-принятия-решении" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-tree-view&quot;&gt;&lt;/i&gt; Конвейер принятия решений&quot;">​</a></h2><p>Архитектура плагина строго разделяет сбор данных, принятие решений и их исполнение.</p><h3 id="_1-tracker-наблюдатель" tabindex="-1">1. Tracker (Наблюдатель) <a class="header-anchor" href="#_1-tracker-наблюдатель" aria-label="Permalink to &quot;1. Tracker (Наблюдатель)&quot;">​</a></h3><p>Каждый кадр Tracker собирает сырые данные о времени кадра и чистом процессорном времени. Он вычисляет скользящее среднее (Moving Average), чтобы сгладить случайные спайки от Garbage Collector&#39;а или подгрузки ассетов.<br> Трекер не принимает решений, он лишь отвечает на два вопроса:</p><ul><li><em>&quot;Успеваем ли мы за Target Min FPS?&quot;</em></li><li><em>&quot;Какая именно подсистема сейчас тормозит (Bottleneck)?&quot;</em></li></ul><h3 id="_2-indexer-мозг" tabindex="-1">2. Indexer (Мозг) <a class="header-anchor" href="#_2-indexer-мозг" aria-label="Permalink to &quot;2. Indexer (Мозг)&quot;">​</a></h3><p>Indexer принимает данные от Tracker и решает, что с этим делать. Это арбитр системы.<br> Если FPS падает, Indexer:</p><ol><li>Проверяет, не находится ли система в <strong>Cooldown</strong>.</li><li>Проверяет систему штрафов <strong>Anti Yo-Yo</strong> (см. подробнее <a href="./anti-yoyo">Anti Yo-Yo Penalty</a>).</li><li>Вычисляет cтоимость всех доступных Scalers.</li><li>Отдает приказ тому Scaler&#39;у, который даст максимум производительности при минимальном визуальном ущербе.</li></ol><h3 id="_3-scalers-исполнители" tabindex="-1">3. Scalers (Исполнители) <a class="header-anchor" href="#_3-scalers-исполнители" aria-label="Permalink to &quot;3. Scalers (Исполнители)&quot;">​</a></h3><p>Scalers получают приказ от Indexer и делают грязную работу. Они обращаются к API Unity и применяют нужные настройки (снижают разрешение, отсекают слои, отключают сглаживание).</p><h2 id="bottlenecks-поиск-узких-мест-без-градусников" tabindex="-1"><i class="ph ph-cpu"></i> Bottlenecks: Поиск узких мест без градусников <a class="header-anchor" href="#bottlenecks-поиск-узких-мест-без-градусников" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-cpu&quot;&gt;&lt;/i&gt; Bottlenecks: Поиск узких мест без градусников&quot;">​</a></h2><p>Как WebAP понимает, что именно не справляется с нагрузкой, не имея доступа к датчикам устройства? Мы анализируем пропорции таймингов внутри самого движка.</p><ul><li><strong>CPU Bottleneck:</strong> Трекер делит чистое время работы главного потока процессора на общее время кадра. Если это соотношение превышает <strong>85%</strong>, вывод очевиден. Кадр уперся в вычисления логики или физики. Снижать разрешение экрана или отключать тени бесполезно.</li><li><strong>GPU Bottleneck:</strong> Если общий FPS ниже нормы, но при этом доля CPU составляет менее 85%, значит процессор простаивает. Видеокарта не успевает отрисовать кадр (упор в Fillrate, сложные шейдеры или Overdraw).</li><li><strong>Target Frame Rate:</strong> Если среднее время ожидания VSync больше нуля, значит и процессор, и видеокарта успевают всё отрисовать быстрее частоты обновления монитора. Система работает с запасом мощности, и Indexer может плавно повышать качество графики.</li></ul><h2 id="zero-gc-производительность-прежде-всего" tabindex="-1"><i class="ph-fill ph-lightning"></i> Zero-GC: Производительность прежде всего <a class="header-anchor" href="#zero-gc-производительность-прежде-всего" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-lightning&quot;&gt;&lt;/i&gt; Zero-GC: Производительность прежде всего&quot;">​</a></h2><p>Плагин, спасающий игру от лагов, не имеет права лагать сам. Ядро WebAP спроектировано с учетом жесткой экономии памяти (Zero-GC) в горячем цикле выполнения (Hot Path).</p><ul><li><strong>Кольцевые буферы O(1):</strong> Вместо <code>List&lt;float&gt;</code> и тяжелых циклов в <code>Update</code>, Трекер использует массивы фиксированного размера (Ring Buffers). Расчет среднего FPS выполняется за константное время.</li><li><strong>Без аллокаций в <code>Update</code>:</strong> В ядре нет вызовов <code>new</code>, боксинга или лямбд. Мусоросборщику (Garbage Collector) просто нечего чистить.</li><li><strong>Кэширование делегатов:</strong> Даже для сложных задач (перехват кликов в <code>WebScaledPhysics2DRaycaster</code>) мы отказались от медленной рефлексии (<code>MethodInfo.Invoke</code>) в пользу быстрых скомпилированных делегатов.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title"><i class="ph-bold ph-note-pencil"></i> Незаметность</p><p>Благодаря этим оптимизациям накладные расходы на работу всего конвейера WebAP минимальны. Ваш процессор даже не заметит, что за ним следят.</p></div>',20)])])}const u=t(l,[["render",i]]);export{g as __pageData,u as default};
